What does the following program print?

```cpp
#include <iostream>

class Base {
public:
    virtual void foo() const { std::cout << "Base\n"; }
};

class Derived : public Base {
public:
    void foo() const override { std::cout << "Derived\n"; }
};

int main() {
    Derived d;
    Base b = d;    // copy by value
    b.foo();
}
```

What does this program print?

```cpp
#include <iostream>

class Animal {
public:
    virtual void speak() const { std::cout << "Animal\n"; }
};

class Dog : public Animal {
public:
    void speak() const override {
        Animal::speak();
        std::cout << "Dog\n";
    }
};

int main() {
    Dog d;
    Animal* p = &d;
    p->speak();
}
```

